	tmLanguage := `{
  "scopeName": "source.drift",
  "patterns": [
    { "match": "\\b(fun|val|var|set|if|else)\\b", "name": "keyword.control.drift" },
    { "match": "\\b(App|Column|Row|Box|Text|TextField|Button|Toast)\\b", "name": "entity.name.class.drift" },
    { "match": "\\b(Modifier|Color|TextStyle|TextFieldDefaults|ToastType|ToastLength|PasswordVisualTransformation)\\b", "name": "support.class.drift" },
    { "match": "\\b(scaledSp|scaledDp|useNav|useToast)\\b", "name": "support.function.drift" },
    { "match": "\"[^\"]*\"", "name": "string.quoted.double.drift" },
    { "match": "@State\\b", "name": "storage.modifier.drift" },
    { "match": "\\b[0-9]+(f|dp|sp)?\\b", "name": "constant.numeric.drift" }
  ]
}`
	os.WriteFile(filepath.Join(syntaxDir, "drift.tmLanguage.json"), []byte(tmLanguage), 0644)

	langConfig := `{
    "comments": { "lineComment": "//", "blockComment": ["/*", "*/"] },
    "brackets": [ ["{", "}"], ["[", "]"], ["(", ")"] ],
    "autoClosingPairs": [
        {"open": "{", "close": "}"},
        {"open": "[", "close": "]"},
        {"open": "(", "close": ")"},
        {"open": "\"", "close": "\"", "notIn": ["string"]}
    ],
    "surroundingPairs": [ ["{", "}"], ["[", "]"], ["(", ")"], ["\"", "\""] ],
    "indentationRules": {
        "increaseIndentPattern": "^.*\\{[^}\"']*$|^.*\\([^)\"']*$",
        "decreaseIndentPattern": "^\\s*[\\}\\]\\)]\\s*$"
    }
}`
